function validateForm() {
  const pickup = document.getElementById("pickupAddress").value.trim();
  const dropoff = document.getElementById("dropoffAddress").value.trim();
  const passengers = document.getElementById("passengers").value;
  if (pickup.length < 3) {
    requestAnimationFrame(() => document.getElementById("pickupAddress").focus());
    return false;
  }
  if (dropoff.length < 3) {
    requestAnimationFrame(() => document.getElementById("dropoffAddress").focus());
    return false;
  }
  if (!passengers || Number(passengers) < 1) {
    requestAnimationFrame(() => document.getElementById("passengers").focus());
    return false;
  }
  return true;
}

function trackGoogleAdsConversion() {
  console.log("Google Ads Conversion Triggered");
}

document.addEventListener('DOMContentLoaded', () => {
  const quoteForm = document.getElementById('quote-form');
  if (!quoteForm) return;

  quoteForm.addEventListener('submit', async function (e) {
    e.preventDefault();

    const submitBtn = document.getElementById('submitBtn');
    const originalText = submitBtn.textContent;
    submitBtn.textContent = "Sending...";
    submitBtn.disabled = true;

    if (!validateForm()) {
      submitBtn.textContent = originalText;
      submitBtn.disabled = false;
      return;
    }

    // Map HTML name attributes to EmailJS template variables
    const templateParams = {
      client_name: this.querySelector('[name="Full_Name"]')?.value || '',
      client_email: this.querySelector('[name="email"]')?.value || '',
      phone: this.querySelector('[name="Phone_Number"]')?.value || '',
      passengers: this.querySelector('[name="Passengers"]')?.value || '',
      vehicle_type: this.querySelector('[name="Vehicle_Type"]')?.value || '',
      service_type: this.querySelector('[name="Service_Type"]')?.value || '',
      pickup: this.querySelector('[name="Pickup_Location"]')?.value || '',
      dropoff: this.querySelector('[name="Drop_Off_Location"]')?.value || '',
      date_time: (this.querySelector('[name="Pickup_Date"]')?.value || '') + " at " + (this.querySelector('[name="Pickup_Time"]')?.value || '')
    };

    const payload = {
      service_id: 'service_05obng6',
      template_id: 'template_mupr0xf',
      user_id: '_4emOGNfMrl5llxnP',
      template_params: templateParams
    };

    try {
      const response = await fetch('https://api.emailjs.com/api/v1.0/email/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (response.ok) {
        console.log("Form submitted successfully");
        trackGoogleAdsConversion();

        // Hide form, show success message
        this.style.setProperty('display', 'none', 'important');
        const successMsg = document.getElementById('success-message');
        if (successMsg) {
          successMsg.style.setProperty('display', 'flex', 'important');
        }
        this.reset();
      } else {
        console.error("EmailJS Error Response");
        alert("Server Error: Please try again later or contact us directly.");
      }
    } catch (error) {
      console.error("Fetch Error:", error);
      alert("Network error: Please check your connection and try again.");
    } finally {
      submitBtn.textContent = originalText;
      submitBtn.disabled = false;
    }
  });

  // Handle the "Make Another Reservation" reset button
  const resetBtn = document.getElementById('reset-form-btn');
  if (resetBtn) {
    resetBtn.addEventListener('click', function () {
      const successMsg = document.getElementById('success-message');
      if (successMsg) successMsg.style.setProperty('display', 'none', 'important');
      quoteForm.style.setProperty('display', 'grid', 'important');
    });
  }
});
